--
-- Table structure for table `proposal`
--

DROP TABLE IF EXISTS `proposal`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `proposal` (
  `id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT (uuid()),
  `title` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `description` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `category_id` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `user_id` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `municipality_id` int NOT NULL,
  `community_id` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `status` enum('rascunho','publicado','arquivado') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'rascunho',
  `visibility` enum('público','privado') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'público',
  `tags` json DEFAULT NULL,
  `goal_supporters` int DEFAULT NULL,
  `views_count` int NOT NULL DEFAULT '0',
  `upvotes_count` int NOT NULL DEFAULT '0',
  `downvotes_count` int NOT NULL DEFAULT '0',
  `score` int GENERATED ALWAYS AS ((`upvotes_count` - `downvotes_count`)) STORED,
  `created_at` datetime(6) NOT NULL DEFAULT (now(6)),
  `updated_at` datetime(6) NOT NULL DEFAULT (now(6)) ON UPDATE CURRENT_TIMESTAMP(6),
  `published_at` datetime(6) DEFAULT NULL,
  `expires_at` datetime(6) DEFAULT NULL,
  `allow_anonymous` tinyint(1) NOT NULL DEFAULT '0',
  PRIMARY KEY (`id`),
  KEY `idx_proposal_category` (`category_id`),
  KEY `idx_proposal_user` (`user_id`),
  KEY `idx_proposal_municipality` (`municipality_id`),
  KEY `idx_proposal_community` (`community_id`),
  KEY `idx_proposal_expires_at` (`expires_at`),
  KEY `idx_proposal_allow_anonymous` (`allow_anonymous`),
  CONSTRAINT `fk_proposal_category` FOREIGN KEY (`category_id`) REFERENCES `category` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `fk_proposal_community` FOREIGN KEY (`community_id`) REFERENCES `community` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `fk_proposal_municipality` FOREIGN KEY (`municipality_id`) REFERENCES `municipality` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `fk_proposal_user` FOREIGN KEY (`user_id`) REFERENCES `app_user` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

