CREATE TABLE `proposal_share` (
  `id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT (uuid()),
  `proposal_id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `shared_by` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `shared_with_email` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `shared_with_representative_id` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `method` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL,
  `message` text COLLATE utf8mb4_unicode_ci,
  `shared_at` datetime(6) NOT NULL DEFAULT (now(6)),
  PRIMARY KEY (`id`),
  KEY `fk_share_rep` (`shared_with_representative_id`),
  KEY `idx_share_proposal` (`proposal_id`),
  KEY `idx_share_user` (`shared_by`),
  CONSTRAINT `fk_share_by` FOREIGN KEY (`shared_by`) REFERENCES `app_user` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `fk_share_proposal` FOREIGN KEY (`proposal_id`) REFERENCES `proposal` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_share_rep` FOREIGN KEY (`shared_with_representative_id`) REFERENCES `parliamentarian` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
